import Papa from 'papaparse'
import ShortUniqueId from 'short-unique-id'
import appsync from '@/api/appsync'
import router from '@/router'
import storage from '@/api/storage'
import { CsvProcessor } from '@/utils'

const uid = new ShortUniqueId()

const state = {
  listingId: null,
  listingName: null,
  reservationCode: null,
  identityId: null,
  listings: [],
  reservations: [],
  members: [],
  events: [],
  createEventsubscription: null
}

const actions = {
  async loadListings ({ commit, dispatch, rootState }) {
    // console.log('rootState.session', rootState.session)

    const rtn = await appsync.getListings(rootState.session.hostId)
    // console.log('listings', listings)

    if (rtn.errors) {
      return rtn.errors[0]
    } else {
      const listings = rtn.data.getListings

      commit('setListings', listings)
    }
  },
  async createListing ({ commit, state, rootState }, val) {
    val.hostId = rootState.session.hostId
    val.listingId = uid.randomUUID(6)
    const rtn = await appsync.createListing(val)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      // console.log('members', members)
      const listing = rtn.data.createListing

      state.listings.push(listing)
    }
  },
  async updateListing ({ commit, state }, val) {
    const rtn = await appsync.updateListing(val.params)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      // console.log('members', members)
      const listing = rtn.data.updateListing

      Object.assign(state.listings[val.index], listing)
    }
  },
  async loadReservations ({ commit }, listingId) {
    const rtn = await appsync.getReservations(listingId)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      const reservations = rtn.data.getReservations

      commit('setReservations', reservations)
    }
  },
  async loadMembers ({ commit }, reservationCode) {
    const rtn = await appsync.getMembers(reservationCode)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      const members = rtn.data.getMembers

      commit('setMembers', members)
    }
    
  },
  async updateMember ({ commit, state }, val) {
    const rtn = await appsync.updateMember(val)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      const member = rtn.data.updateMember

      const index = member.memberNo - 1
      Object.assign(state.members[index], member)
      
    }
  },
  async updateReservation ({ commit, state }, val) {
    console.log('updateReservation val', val.params)

    const rtn = await appsync.updateReservation(val.params)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      const reservation = rtn.data.updateReservation

      Object.assign(state.reservations[val.index], reservation)
    }
  },
  async generateReservation ({ commit, state }, val) {
    // console.log('generateReservation val', JSON.stringify(val))
    const rtn = await appsync.generateReservation(val)
    // console.log('generateReservation rtn', rtn)

    if (rtn.errors) {
      throw rtn.errors[0]
    } else {
      const reservation = rtn.data.generateReservation

      state.reservations.push(reservation)
    }
  },
  pickListing ({ commit }, val) {
    console.log('pickListing', val)

    commit('setListingId', val.listingId)
    commit('setListingName', val.listingName)
    

    router.push({path: '/reservations'})
  },
  pickReservation ({ commit }, val) {
    console.log('pickReservation', val)
    console.log('this.$route', router.currentRoute)

    commit('setReservationCode', val.reservationCode)
    commit('setIdentityId', val.identityId)

    if (router.currentRoute.name === 'members') {
      router.go()
    } else {
      router.push({path: '/members'})
    }
    
  },
  async uploadJson ({ commit, dispatch }, { fileObject, listingId }) {
    console.log('uploadJson', fileObject)

    const result = await dispatch('parseFile', fileObject)
    console.log('result', result)

    await storage.putJson(uid.randomUUID(8) + '.json', { reservations: result, listingId })
  },
  readFile ({ commit }, fileObject) {
    return new Promise((resolve, reject) => {

        const reader = new FileReader()
        reader.onload = (event) => {
            resolve(event.target.result)
        }

        reader.readAsArrayBuffer(fileObject)
    })
  },
  parseFile ({ commit }, fileObject) {
    return new Promise((resolve, reject) => {

      Papa.parse(fileObject, {
        header: true,
        beforeFirstChunk: chunk => {
            const rows = chunk.split( /\r\n|\r|\n/ )
            const headings = rows[0].split( ',' )

            const newHeadings = CsvProcessor.transformHeaderAirbnb(headings)

            rows[0] = newHeadings.join()
            return rows.join( '\n' )
        },
        transform: (value, columnNo) => {
          
          const test = CsvProcessor.transformAirbnb(value, columnNo)
          return test
        },
        complete: results => {
          //todo getrid of erro by results.error
          resolve(results.data)
        }
      })

    })
  },
  async subscribeCreateEvent ({ commit, state, rootState, dispatch }) {
    console.log('subscribeCreateEvent rootState.session.hostId', JSON.stringify(rootState.session.hostId))

    if (rootState.session.hostId) {
      console.log('this.subscription', this.subscription)
      // console.log('this.subscription', this.subscription._state)
      if (!this.subscription || this.subscription.closed) {

        const rtn = await appsync.onCreateEvent(rootState.session.hostId)
        if (rtn.errors) {
          throw rtn.errors[0]
        } else {
          console.log('before subscribe', rtn)
          this.subscription = rtn.subscribe({
            next: (eventData) => {
              console.log('eventData: ', eventData)
              dispatch('addEvent', eventData.value.data.onCreateEvent)
            }
          })

          console.log('subscription', this.subscription)
        }        
      }
    }
  },
/*
  async subscribeCreateEvent ({ commit, state, rootState, dispatch }) {
    console.log('subscribeCreateEvent rootState.session.hostId', JSON.stringify(rootState.session.hostId))

    if (rootState.session.hostId) {
      console.log('state.createEventsubscription', state.createEventsubscription)
      if (!state.createEventsubscription) {
        console.log('onCreateEvent')
        const rtn = await appsync.onCreateEvent(rootState.session.hostId)
        if (rtn.errors) {
          throw rtn.errors[0]
        } else {
          console.log('before subscribe', rtn)
          const subscription = rtn.subscribe({
            next: (eventData) => {
              console.log('eventData: ', eventData)
              dispatch('addEvent', eventData.value.data.onCreateEvent)
            }
          })

          console.log('subscription', subscription)

          commit('setCreateEventsubscription', subscription)

          console.log('after subscription', state.createEventsubscription)
        }
      }
    }
  },
*/
  addEvent ({ state }, onCreateEventData) {
    // commit('setEvents', onCreateEventData)

    state.events.push(onCreateEventData)

    console.log('state.events.length', state.events.length)
  },
  unsubscribeCreateEvent ({ commit, rootState, dispatch }) {
    if (state.createEventsubscription) {
      state.createEventsubscription.unsubscribe()
      state.createEventsubscription = null
      state.events.length = 0
    }
  },
  removeEvent ({ state }, event) {
    // commit('setEvents', onCreateEventData)
    

    const index = state.events.indexOf(event);
    if (index > -1) {
      state.events.splice(index, 1);
    }

    console.log('state.events.length', state.events.length)
  },
}

const mutations = {
  setCreateEventsubscription(state, val) {
    state.createEventsubscription = val
  },
  setMembers(state, val) {
    state.members = val
  },
  setReservations(state, val) {
    state.reservations = val
  },
  setListings(state, val) {
    state.listings = val
  },
  setListingId(state, val) {
    state.listingId = val
  },
  setListingName(state, val) {
    state.listingName = val
  },
  setReservationCode(state, val) {
    state.reservationCode = val
  },
  setIdentityId(state, val) {
    state.identityId = val
  }

}

const subscription = null

const getters = {}

export default {
  namespaced: true,
  state,
  getters,
  actions,
  mutations
}