import Vue from 'vue'
import Router from 'vue-router'
import { components, AmplifyEventBus } from 'aws-amplify-vue'
import store from '@/store'
// import Listings from '@/views/Listings.vue'
const Listings = () => import('@/views/Listings.vue')
// import Reservations from '@/views/Reservations.vue'
const Reservations = () => import('@/views/Reservations.vue')
// import Members from '@/views/Members.vue'
const Members = () => import('@/views/Members.vue')

const About = () => import('@/views/About.vue')

Vue.use(Router)

AmplifyEventBus.$on('authState', async (state) => {
  console.log('AmplifyEventBus.$on', state)

  if (state === 'signedOut'){
    console.log('signedOut')

    store.dispatch('host/unsubscribeCreateEvent')
      .catch(e => console.log('unsubscribeCreateEvent!!!', e))

    router.push({path: '/auth'})
  } else if (state === 'signedIn') {
    // console.log('signedIn')

    await store.dispatch('session/login')
      .catch(e => console.log('login!!!', e))

    // await store.dispatch('host/subscribeCreateEvent')
    //   .catch(e => console.log('subscribeCreateEvent!!!', e))


    router.push({path: '/listings'})
  }
})

const router = new Router({
  mode: 'history',
  // base: process.env.BASE_URL,
  routes: [
    {
      path: '/listings',
      name: 'listings',
      component: Listings,
      alias: '/',
      meta: { requiresAuth: true }
    },
    {
      path: '/reservations',
      name: 'reservations',
      component: Reservations,
      meta: { requiresAuth: true }
    },
    {
      path: '/members',
      name: 'members',
      component: Members,
      meta: { requiresAuth: true }
    },
    {
      path: '/about',
      name: 'about',
      component: About,
      meta: { requiresAuth: true }
    },
    {
      path: '/auth',
      name: 'Authenticator',
      component: components.Authenticator,
    },
  ]
})

router.beforeEach(async (to, from, next) => {

  // console.log("beforeEach store.state.session", JSON.stringify(store.state.session))
  // console.log("beforeEach store.state.host",store.state.host)

  if (to.matched.some(record => record.meta.requiresAuth)) {

    if (!store.state.session.hostId) {
      await store.dispatch('session/logout')
        .catch(e => console.log('login!!!', e))
    }

    return next()
  }

  return next()
})

router.afterEach((to, from, next) => {

    store.dispatch('host/subscribeCreateEvent')
      .catch(e => console.log('subscribeCreateEvent', e))


})

export default router